VALUES
  ('bookkeeper-moex-01429', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，商業負責人、主辦及經辦會計人員或依法受託代他人處理會計事務之 人員有下列情事之一者，處五年以下有期徒刑、拘役或科或併科新臺幣六十萬元以下罰金，但不包括下列 那一情事？', '["以明知為不實之事項，而填製會計憑證或記入帳冊", "偽造或變造會計憑證、會計帳簿報表內容或毀損其頁數", "未依法取得代他人處理會計事務之資格而擅自代他人處理商業會計事務", "故意遺漏會計事項不為記錄，致使財務報表發生不實之結果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01430', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，下列有關會計憑證之敘述何者錯誤？', '["對外憑證之正本或存根均應依次編定字號，並應將其副本或存根，裝訂成冊；其正本之誤寫或收回作廢者， 可以不必將其黏附於原號副本或存根之上", "記帳憑證及會計帳簿，應由代表商業之負責人、經理人、主辦及經辦會計人員簽名或蓋章負責", "記帳憑證得由代表商業之負責人授權經理人、主辦或經辦會計人員簽名或蓋章", "會計憑證，應按日或按月裝訂成冊，有原始憑證者，應附於記帳憑證之後"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01431', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，下列敘述何者錯誤？', '["金融工具投資應視其性質採公允價值、成本或攤銷後成本之方法衡量", "存貨以成本與淨變現價值孰低衡量，當存貨成本高於淨變現價值時，應將成本沖減至淨變現價值", "上述存貨沖減金額應於發生當期認列為營業費用", "具有控制能力或重大影響力之長期股權投資，採用權益法處理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01432', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，下列敘述何者錯誤？', '["資產及負債之原始認列，以成本衡量為原則", "商業在決定財務報表之會計項目金額時，應視實際情形，選擇適當之衡量基礎，但不得以歷史成本衡量", "資產之取得，係由非貨幣性資產交換而來者，以公允價值衡量為原則。但公允價值無法可靠衡量時，以換 出資產之帳面金額衡量", "受贈資產按公允價值入帳，並視其性質列為資本公積、收入或遞延收入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01433', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，下列敘述何者錯誤？', '["報導期間經濟效益之減少，以資產流出、消耗或負債增加等方式減少權益，是為權益", "因過去事項所產生之資源，該資源由商業控制，並預期帶來經濟效益之流入，是為資產", "因過去事項所產生之現時義務，預期該義務之清償，將導致經濟效益之資源流出，是為負債", "報導期間經濟效益之增加，以資產流入、增值或負債減少等方式增加權益（但不含業主投資而增加之權 益），是為收益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01434', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，各項會計帳簿及財務報表，除有關未結會計事項者外，應於年度決算 程序辦理終了後，至少保存多少年？', '["一年", "三年", "五年", "十年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01435', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，會計事項應按發生次序逐日登帳，至遲不得超過多久的時間？', '["二天", "一星期", "一個月", "二個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01436', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業登記法第3條規定，商業之完整定義是指下列何者？', '["獨資組織之營利事業", "獨資、合夥組織之營利事業", "公司", "公司或獨資、合夥組織之營利事業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01437', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法之規定，下列敘述何者錯誤？', '["商業會計之記載，除記帳數字適用阿拉伯字外，應以我國文字為之", "商業會計之記載因事實上之需要，而須加註或併用外國文字，或當地通用文字者，仍以我國文字為準", "商業應以國幣為記帳本位", "但因業務實際需要，而以外國貨幣記帳者，允許在其決算報表中以外國貨幣表達，免將外國貨幣折合國幣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01438', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '某甲是開心有限公司負責人，依據我國最新修正商業會計法第68條規定，其應於會計年度終了後幾個月內， 將公司之決算報表提請股東承認？', '["三個月", "六個月", "一個月", "二個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01439', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國最新修正商業會計法第58條規定，商業在同一會計年度內所發生之全部收益，減除同期之全部成 本、費用及損失後之差額是指下列何者？', '["本期綜合損益總額", "本期營業淨利", "本期稅前純益", "本期稅後純益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
